$('createHome').onsubmit=async e=>{e.preventDefault();const name=new FormData(e.currentTarget).get('name'),hid=uid(),code=Math.random().toString(36).slice(2,8).toUpperCase(),b=writeBatch(db);b.set(doc(db,'households',hid),{name,createdBy:user.uid,createdAt:serverTimestamp(),inviteCode:code});b.set(doc(db,'households',hid,'members',user.uid),{name:user.displayName||user.email,email:user.email,role:'owner'});b.set(doc(db,'invites',code),{householdId:hid,status:'active',createdBy:user.uid,uses:0});b.set(doc(db,'users',user.uid),{name:user.displayName||user.email,email:user.email,householdId:hid,inviteCode:code},{merge:true});await b.commit();connect({householdId:hid,inviteCode:code})};
$('joinHome').onsubmit=async e=>{e.preventDefault();const code=String(new FormData(e.currentTarget).get('code')).toUpperCase(),i=await getDoc(doc(db,'invites',code));if(!i.exists())return toast('Código no válido');const d=i.data(),b=writeBatch(db);b.set(doc(db,'households',d.householdId,'members',user.uid),{name:user.displayName||user.email,email:user.email,role:'member'});b.set(doc(db,'users',user.uid),{name:user.displayName||user.email,email:user.email,householdId:d.householdId,inviteCode:code},{merge:true});b.update(doc(db,'invites',code),{uses:increment(1)});await b.commit();connect({householdId:d.householdId,inviteCode:code})};
function catalog(){const map=new Map(CATALOG.map(x=>[x.id,x]));state.customCatalog.forEach(x=>map.set(x.id,x));return [...map.values()]}
function price(x){const p=catalog().find(p=>p.id===x.productId);return num(x.unitPrice)||(p?num(p[state.preferredStore]):0)}
function monthKey(dateValue=today()){return String(dateValue||today()).slice(0,7)}
function purchaseDateOf(x){if(x.purchaseDate)return x.purchaseDate;const e=x.linkedExpenseId&&state.expenses.find(e=>e.id===x.linkedExpenseId);return e?.date||''}
function currentMonthPurchasedRows(){const ym=monthKey();return state.shopping.filter(x=>x.done&&monthKey(purchaseDateOf(x))===ym)}
function isMarketExpense(e){const cat=norm(e?.category||''),title=norm(e?.title||e?.description||'');return Boolean(e?.sourcePurchaseId||cat==='mercado'||cat.includes('mercado')||title.startsWith('mercado'))}
function currentMonthMarketExpenses(){const ym=monthKey();return state.expenses.filter(e=>monthKey(e.date||e.createdAt||'')===ym&&isMarketExpense(e))}
function currentMonthMarketSpent(){
  const expenses=currentMonthMarketExpenses();
  const expenseIds=new Set(expenses.map(e=>e.id).filter(Boolean));
  const purchaseIds=new Set(expenses.map(e=>e.sourcePurchaseId).filter(Boolean));
  let total=expenses.reduce((sum,e)=>sum+num(e.amount),0);
  // Compatibilidad: suma compras realizadas que no tengan gasto enlazado o cuyo gasto antiguo haya desaparecido.
  for(const x of currentMonthPurchasedRows()){
    const linkedExists=(x.linkedExpenseId&&expenseIds.has(x.linkedExpenseId))||purchaseIds.has(x.id);
    if(!linkedExists)total+=num(x.actualTotal||num(x.qty)*price(x));
  }
  return total;
}
function currentMonthMarketPurchaseCount(){
  const expenses=currentMonthMarketExpenses();
  const purchaseIds=new Set(expenses.map(e=>e.sourcePurchaseId||e.id).filter(Boolean));
  for(const x of currentMonthPurchasedRows())purchaseIds.add(x.id);
  return purchaseIds.size;
}
function pendingMarket(){return state.shopping.filter(x=>!x.done).reduce((s,x)=>s+num(x.qty)*price(x),0)}
function marketBudgetStatus(){const budget=num(state.budget),spent=currentMonthMarketSpent(),pending=marketTotals()[state.preferredStore],projected=spent+pending,remaining=budget-projected;return{budget,spent,pending,projected,remaining,purchasedCount:currentMonthMarketPurchaseCount(),pendingCount:state.shopping.filter(x=>!x.done).length,month:monthKey()}}
function monthExpenses(){const ym=today().slice(0,7);return state.expenses.filter(x=>String(x.date||'').startsWith(ym)).reduce((s,x)=>s+num(x.amount),0)}function monthlyFixedAmount(x){const a=num(x.amount);const f=x.frequency||'monthly';return f==='weekly'?a*4.33:f==='biweekly'?a*2:f==='annual'?a/12:a}function fixedTotal(){return state.fixedExpenses.filter(x=>x.active!==false).reduce((s,x)=>s+monthlyFixedAmount(x),0)}function incomeTotal(){return state.salaryPayments.filter(x=>x.active!==false).reduce((s,x)=>s+num(x.amount),0)+state.extraIncomes.filter(x=>String(x.date||'').startsWith(today().slice(0,7))).reduce((s,x)=>s+num(x.amount),0)}

const STORE_LABELS={market:'Mercado',supermarket:'Supermercado',wholesale:'Mayorista'};
function productRecord(x){return catalog().find(p=>p.id===x.productId)||catalog().find(p=>norm(p.name)===norm(x.title||x.name))||null}
function productEmoji(x){const n=norm(x?.title||x?.name||''),c=norm(x?.category||productRecord(x)?.category||'');const rules=[['sandia','🍉'],['melon','🍈'],['platano','🍌'],['banana','🍌'],['manzana','🍎'],['pera','🍐'],['naranja','🍊'],['mandarina','🍊'],['limon','🍋'],['uva','🍇'],['fresa','🍓'],['arandano','🫐'],['mango','🥭'],['pina','🍍'],['palta','🥑'],['tomate','🍅'],['papa','🥔'],['zanahoria','🥕'],['cebolla','🧅'],['ajo','🧄'],['brocoli','🥦'],['lechuga','🥬'],['pepino','🥒'],['aji','🌶️'],['rocoto','🌶️'],['arroz','🍚'],['pan','🍞'],['huevo','🥚'],['leche','🥛'],['queso','🧀'],['pollo','🍗'],['carne','🥩'],['pescado','🐟'],['atun','🐟'],['agua','💧'],['gaseosa','🥤'],['jugo','🧃'],['cafe','☕'],['chocolate','🍫'],['galleta','🍪'],['caramelo','🍬'],['helado','🍨'],['detergente','🧴'],['jabon','🧼'],['papel','🧻'],['olla','🍲'],['sarten','🍳'],['cuchillo','🔪'],['mascota','🐾']];for(const [k,e] of rules)if(n.includes(k))return e;if(c.includes('fruta'))return'🍎';if(c.includes('verdura'))return'🥬';if(c.includes('carne')||c.includes('pescado'))return'🥩';if(c.includes('lacteo'))return'🥛';if(c.includes('limpieza'))return'🧼';if(c.includes('dulce')||c.includes('snack'))return'🍪';if(c.includes('hogar')||c.includes('cocina'))return'🏠';return'🛒'}
function productImage(x){const e=productEmoji(x),name=String(x?.title||x?.name||'Producto').replace(/[<>&\"']/g,'');const palette=['#E8F3FF','#FFF1E7','#EAF8EE','#F4ECFF','#FFF6D9'];let h=0;for(const ch of name)h=(h+ch.charCodeAt(0))%palette.length;const svg=`<svg xmlns="http://www.w3.org/2000/svg" width="180" height="180" viewBox="0 0 180 180"><rect width="180" height="180" rx="42" fill="${palette[h]}"/><circle cx="90" cy="78" r="52" fill="white" fill-opacity=".72"/><text x="90" y="100" font-size="72" text-anchor="middle">${e}</text><text x="90" y="153" font-family="-apple-system,Arial" font-size="14" font-weight="700" text-anchor="middle" fill="#344054">${name.slice(0,18)}</text></svg>`;return'data:image/svg+xml;charset=UTF-8,'+encodeURIComponent(svg)}
function marketTotals(){const rows=state.shopping.filter(x=>!x.done);const totals={market:0,supermarket:0,wholesale:0,min:0,max:0,count:rows.length};for(const x of rows){const p=productRecord(x),q=num(x.qty);for(const k of ['market','supermarket','wholesale'])totals[k]+=q*(p?num(p[k]):price(x));const probable=q*price(x),mn=p?num(p.minFactor)||.85:.85,mx=p?num(p.maxFactor)||1.18:1.18;totals.min+=probable*mn;totals.max+=probable*mx}return totals}
function financeProjection(){const income=incomeTotal(),fixed=fixedTotal(),spent=monthExpenses(),market=pendingMarket(),available=income-fixed-spent-market;return{income,fixed,spent,market,available,commitments:fixed+spent+market}}
function nextSalary(){const d=new Date(),day=d.getDate(),active=state.salaryPayments.filter(x=>x.active!==false).sort((a,b)=>num(a.day)-num(b.day));let p=active.find(x=>num(x.day)>=day);let monthShift=0;if(!p){p=active[0];monthShift=1}if(!p)return null;const date=new Date(d.getFullYear(),d.getMonth()+monthShift,Math.min(num(p.day),new Date(d.getFullYear(),d.getMonth()+monthShift+1,0).getDate()));return{...p,date,days:Math.max(0,Math.ceil((date-d)/86400000))}}
function compareSheet(id){const x=state.shopping.find(v=>v.id===id);if(!x)return;const p=productRecord(x);if(!p)return toast('Este producto aún no tiene precios de catálogo');const q=num(x.qty);openSheet('Comparar precios',`<div class="product-detail"><img src="${productImage(x)}" alt="${x.title}"><div><small>${p.category||'Producto'}</small><h2>${x.title}</h2><p>${q} ${x.unit}</p></div></div><div class="compare-list">${['market','supermarket','wholesale'].map(k=>`<button class="compare-row ${state.preferredStore===k?'best-active':''}" data-use-store="${k}"><span><small>${STORE_LABELS[k]}</small><b>${money(num(p[k]))} / ${p.unit}</b></span><strong>${money(q*num(p[k]))}</strong></button>`).join('')}</div><div class="range-card"><span>Rango referencial</span><b>${money(q*num(p.market)*(num(p.minFactor)||.85))} – ${money(q*num(p.supermarket)*(num(p.maxFactor)||1.18))}</b></div>`);document.querySelectorAll('[data-use-store]').forEach(b=>b.onclick=()=>{state.preferredStore=b.dataset.useStore;x.unitPrice=num(p[b.dataset.useStore]);closeSheet();persist();toast('Precio actualizado')})}

function safe(module,fn){try{return fn()}catch(e){console.error(module,e);return `<div class="card error-card"><h3>No se pudo mostrar ${module}</h3><p class="muted">Tus datos siguen seguros.</p><button class="primary" onclick="location.reload()">Reintentar</button></div>`}}
const titles={home:'Mi Hogar',market:'Mercado',pantry:'Despensa',agenda:'Agenda',more:'Más'};function go(v){currentView=v;$('pageTitle').textContent=titles[v];document.querySelectorAll('#nav button').forEach(b=>b.classList.toggle('active',b.dataset.view===v));render()}$('nav').onclick=e=>{const b=e.target.closest('button[data-view]');if(b)go(b.dataset.view)};
function render(){if(!$('app')||$('app').hidden)return;$('view').innerHTML=safe(currentView,()=>({home:homeView,market:marketView,pantry:pantryView,agenda:agendaView,more:moreView}[currentView])());bindView();updateNotificationBadge()}
function homeView(){const f=financeProjection(),low=state.pantry.filter(x=>num(x.qty)<=num(x.minQty)).length,next=nextSalary(),pct=f.income?Math.min(100,f.commitments/f.income*100):0;return `<section class="hero finance-hero ${f.available<0?'negative':''}"><small>PROYECCIÓN DEL MES</small><strong>${money(f.available)}</strong><span>${f.available>=0?'Disponible después de compromisos':'Falta por cubrir con los ingresos programados'}</span><div class="hero-progress"><span style="width:${pct}%"></span></div><div class="hero-foot"><span>${Math.round(pct)}% comprometido</span><span>${next?`Próximo ingreso: ${next.name} en ${next.days} días`:'Configura tus ingresos'}</span></div></section><div class="projection-grid"><div><small>Ingresos</small><b>${money(f.income)}</b></div><div><small>Gastos fijos</small><b>${money(f.fixed)}</b></div><div><small>Ya gastado</small><b>${money(f.spent)}</b></div><div><small>Mercado pendiente</small><b>${money(f.market)}</b></div></div><div class="grid"><button class="card metric" data-go="market"><small>Mercado</small><b>${state.shopping.filter(x=>!x.done).length}</b><span class="muted">pendientes · ${money(f.market)}</span></button><button class="card metric" data-go="pantry"><small>Despensa</small><b>${low}</b><span class="muted">por reponer</span></button><div class="card metric"><small>Tareas</small><b>${state.tasks.filter(x=>!x.done).length}</b><span class="muted">pendientes</span></div><button class="card metric" data-open="finance"><small>Proyección</small><b>${f.available>=0?'✓':'!'}</b><span class="muted">ver detalle mensual</span></button></div><div class="section-head"><h2>Atención hoy</h2></div><div class="list">${state.pantry.filter(x=>num(x.qty)<=num(x.minQty)).slice(0,3).map(pantryCard).join('')||'<div class="card empty">Todo en orden en la despensa.</div>'}</div>`}
const MARKET_CATEGORY_ORDER=['Frutas','Cítricos','Verduras y hortalizas','Tubérculos y raíces','Hierbas y condimentos frescos','Pollo y aves','Carne de res','Carne de cerdo','Pescados','Mariscos','Huevos','Lácteos','Embutidos','Arroz y cereales','Menestras','Pastas y harinas','Aceites y condimentos','Conservas','Abarrotes','Panadería','Repostería e infusiones','Bebidas','Dulces y snacks','Congelados','Limpieza del hogar','Higiene personal','Bebé','Mascotas','Farmacia','Cocina y menaje','Ollas y sartenes','Hogar y organización','Electrodomésticos','Tecnología','Otros'];
function inferMarketCategory(title='',raw='Otros'){
  const n=norm(title),r=norm(raw||'');
  const has=(...keys)=>keys.some(k=>n.includes(k));
  if(has('limon','lima dulce','toronja','mandarina','naranja'))return'Cítricos';
  if(has('papa','camote','yuca','olluco','oca','mashua','arracacha','chuño'))return'Tubérculos y raíces';
  if(has('culantro','perejil','hierbabuena','huacatay','albahaca','romero','menta','kion','ajo','aji amarillo','aji limo','rocoto','apio','poro'))return'Hierbas y condimentos frescos';
  if(has('pollo','pavita','pavo'))return'Pollo y aves';
  if(has('bistec','lomo fino','carne molida','carne para guiso','res','osobuco','mondongo','corazon de res','higado'))return'Carne de res';
  if(has('cerdo','panceta','chuleta','costilla de cerdo'))return'Carne de cerdo';
  if(has('langostino','calamar','pulpo','choro','concha de abanico','marisco','camaron'))return'Mariscos';
  if(has('pescado','bonito','jurel','caballa','merluza','tilapia','salmon','corvina','mero','trucha','pejerrey','anchoveta','atun','conserva de pescado'))return'Pescados';
  if(has('huevo'))return'Huevos';
  if(has('jamon','hot dog','chorizo','salchicha','mortadela','tocino'))return'Embutidos';
  if(has('arroz','avena','quinua','kiwicha','cebada','trigo mote','granola','cereal de maiz','maiz cancha','maiz pop corn'))return'Arroz y cereales';
  if(has('lenteja','frejol','pallar','garbanzo','arveja seca','haba seca'))return'Menestras';
  if(has('fideo','tallarin','spaghetti','harina','maicena','pan rallado'))return'Pastas y harinas';
  if(has('aceite','sal de mesa','vinagre','sillao','mayonesa','mostaza','ketchup','salsa de','miel','mermelada','comino','pimienta','oregano seco','ajinomoto'))return'Aceites y condimentos';
  if(has('conserva','duraznos en almibar','choclo en lata','arvejas en lata','aceituna','pate'))return'Conservas';
  if(has('cafe','cocoa','te','manzanilla','gelatina','flan','leche condensada','manjar','chocolate para taza','vainilla','polvo de hornear','canela','clavo de olor','anis'))return'Repostería e infusiones';
  if(has('olla','sarten','wok','fuente para horno','molde para queque'))return'Ollas y sartenes';
  if(has('plato','vaso','taza','cubierto','cuchillo','tabla de picar','colador','rallador','espatula','cucharon','taper','jarra','termo','secador de cocina','mantel'))return'Cocina y menaje';
  if(has('licuadora','hervidor','tostadora','freidora de aire','olla arrocera','microondas','plancha','ventilador'))return'Electrodomésticos';
  if(has('balde','tacho','cesto','organizador','percha','tendedero','gancho de ropa','sabana','frazada','edredon','almohada','toalla de bano','cortina de bano','foco','extension','multitoma','pila','linterna','espejo','reloj de pared','maceta','regadera'))return'Hogar y organización';
  if(has('paracetamol','ibuprofeno','curita','agua oxigenada','gasa','termometro','mascarilla','repelente'))return'Farmacia';
  if(r==='frutas'||r==='fruta')return'Frutas';
  if(r==='verduras'||r.includes('verdura'))return'Verduras y hortalizas';
  if(r==='carnes y pescados')return'Otros';
  if(r==='limpieza')return'Limpieza del hogar';
  if(r==='higiene')return'Higiene personal';
  return raw||'Otros';
}
function marketItemCategory(x){const p=productRecord(x),raw=String(x.category||p?.category||'Otros').trim();return inferMarketCategory(x.title||x.name||p?.name||'',p?.category||raw)}
function categoryIcon(category){const n=norm(category);if(n==='frutas')return'🍎';if(n.includes('citrico'))return'🍋';if(n.includes('verdura'))return'🥬';if(n.includes('tuberculo'))return'🥔';if(n.includes('hierba'))return'🌿';if(n.includes('pollo'))return'🍗';if(n.includes('res'))return'🥩';if(n.includes('cerdo'))return'🥓';if(n.includes('pescado'))return'🐟';if(n.includes('marisco'))return'🦐';if(n.includes('huevo'))return'🥚';if(n.includes('lacteo'))return'🥛';if(n.includes('embutido'))return'🌭';if(n.includes('arroz')||n.includes('cereal'))return'🌾';if(n.includes('menestra'))return'🫘';if(n.includes('pasta')||n.includes('harina'))return'🍝';if(n.includes('aceite')||n.includes('condimento'))return'🧂';if(n.includes('conserva'))return'🥫';if(n==='abarrotes')return'🛍️';if(n.includes('panader'))return'🥖';if(n.includes('reposteria')||n.includes('infusion'))return'☕';if(n.includes('bebida'))return'🥤';if(n.includes('dulce')||n.includes('snack'))return'🍫';if(n.includes('congelado'))return'❄️';if(n.includes('limpieza'))return'🧼';if(n.includes('higiene'))return'🪥';if(n.includes('bebe'))return'🍼';if(n.includes('mascota'))return'🐾';if(n.includes('farmacia'))return'💊';if(n.includes('olla')||n.includes('sarten'))return'🍳';if(n.includes('menaje')||n.includes('cocina'))return'🍽️';if(n.includes('electrodomestico'))return'🔌';if(n.includes('hogar')||n.includes('organizacion'))return'🏠';if(n.includes('tecnologia'))return'📱';return'📦'}
function sortCategories(categories){return [...categories].sort((a,b)=>{const ia=MARKET_CATEGORY_ORDER.indexOf(a),ib=MARKET_CATEGORY_ORDER.indexOf(b);if(ia!==-1||ib!==-1)return(ia===-1?999:ia)-(ib===-1?999:ib);return a.localeCompare(b,'es')})}
function marketStatusMatch(x){const currentDone=x.done&&monthKey(purchaseDateOf(x))===monthKey();if(marketFilter==='pending')return!x.done;if(marketFilter==='done')return currentDone;if(marketFilter==='favorites')return !x.done&&state.favorites.includes(x.productId);return !x.done||currentDone}
function groupedMarketRows(rows){const map=new Map();for(const x of rows){const c=marketItemCategory(x);if(!map.has(c))map.set(c,[]);map.get(c).push(x)}return sortCategories(map.keys()).map(category=>({category,items:map.get(category)}))}
function marketView(){
  let base=state.shopping.filter(marketStatusMatch);
  if(marketSearch)base=base.filter(x=>norm(x.title).includes(norm(marketSearch))||norm(marketItemCategory(x)).includes(norm(marketSearch)));
  const categories=sortCategories(new Set(base.map(marketItemCategory)));
  if(marketCategory!=='all'&&!categories.includes(marketCategory))marketCategory='all';
  const a=marketCategory==='all'?base:base.filter(x=>marketItemCategory(x)===marketCategory);
  const groups=groupedMarketRows(a),t=marketTotals(),current=t[state.preferredStore],budget=marketBudgetStatus(),best=[['market',t.market],['supermarket',t.supermarket],['wholesale',t.wholesale]].sort((a,b)=>a[1]-b[1])[0];
  const usedPct=budget.budget?Math.min(100,budget.projected/budget.budget*100):0;
  const categoryChips=`<div class="category-scroll" id="marketCategoryFilters"><button data-category="all" class="${marketCategory==='all'?'active':''}">Todos <span>${base.length}</span></button>${categories.map(c=>`<button data-category="${c.replace(/"/g,'&quot;')}" class="${marketCategory===c?'active':''}">${categoryIcon(c)} ${c} <span>${base.filter(x=>marketItemCategory(x)===c).length}</span></button>`).join('')}</div>`;
  const groupedHtml=groups.map(g=>{const subtotal=g.items.reduce((sum,x)=>sum+(x.done?num(x.actualTotal||num(x.qty)*price(x)):num(x.qty)*price(x)),0);return `<section class="market-category-group"><div class="market-category-head"><div><span class="category-emoji">${categoryIcon(g.category)}</span><div><h3>${g.category}</h3><small>${g.items.length} ${g.items.length===1?'producto':'productos'}</small></div></div><b>${money(subtotal)}</b></div><div class="list product-list">${g.items.map(marketCard).join('')}</div></section>`}).join('');
  return `<section class="market-hero monthly-budget"><div class="market-budget-main"><small>PRESUPUESTO DEL MERCADO · ${new Date().toLocaleDateString('es-PE',{month:'long',year:'numeric'}).toUpperCase()}</small><strong>${money(budget.budget)}</strong><span class="${budget.remaining<0?'bad':'good'}">${budget.remaining>=0?`Disponible: ${money(budget.remaining)}`:`Excede por ${money(Math.abs(budget.remaining))}`}</span><div class="market-budget-progress"><span style="width:${usedPct}%"></span></div><p>${Math.round(usedPct)}% comprometido · se reinicia automáticamente el día 1</p></div><div class="market-ring"><b>${budget.pendingCount}</b><small>por comprar</small></div></section>
  <div class="market-month-summary"><div><small>Gastado este mes</small><b>${money(budget.spent)}</b><span>${budget.purchasedCount} comprados</span></div><div><small>Pendiente estimado</small><b>${money(budget.pending)}</b><span>${budget.pendingCount} productos</span></div><div class="${budget.remaining<0?'negative':''}"><small>Saldo del mercado</small><b>${money(budget.remaining)}</b><span>después de todo</span></div></div>
  <div class="market-cycle-actions"><button class="pill-btn" id="marketHistoryBtn">Historial mensual</button><button class="pill-btn" id="editMarketBudget">Editar presupuesto</button></div>
  <div class="estimate-strip"><div><small>Mínimo pendiente</small><b>${money(t.min)}</b></div><div class="primary-est"><small>Probable pendiente · ${STORE_LABELS[state.preferredStore]}</small><b>${money(current)}</b></div><div><small>Máximo pendiente</small><b>${money(t.max)}</b></div></div>
  <div class="store-comparison"><div class="section-head compact"><h2>Comparación de lo pendiente</h2><span class="best-chip">Mejor estimado: ${STORE_LABELS[best[0]]}</span></div><div class="store-cards">${[['market','Mercado'],['supermarket','Supermercado'],['wholesale','Mayorista']].map(([k,l])=>`<button data-store="${k}" class="store-card ${state.preferredStore===k?'active':''}"><small>${l}</small><b>${money(t[k])}</b><span>${t.count?money(t[k]/t.count):money(0)} prom./producto</span></button>`).join('')}</div></div>
  <div class="market-share-bar"><button class="primary share-market-btn" id="shareMarketList">↗ Compartir lista pendiente</button><button class="pill-btn" id="copyMarketQuick">Copiar</button></div><div class="search">⌕<input id="marketSearch" value="${marketSearch}" placeholder="Buscar producto o categoría"></div><div class="segments" id="marketFilters"><button data-filter="pending" class="${marketFilter==='pending'?'active':''}">Pendientes</button><button data-filter="favorites" class="${marketFilter==='favorites'?'active':''}">Favoritos</button><button data-filter="done" class="${marketFilter==='done'?'active':''}">Comprados del mes</button><button data-filter="all" class="${marketFilter==='all'?'active':''}">Todos</button></div>${categoryChips}<div class="market-groups">${groupedHtml||'<div class="card empty">No hay productos en este filtro.</div>'}</div>`}
function marketCard(x){const p=productRecord(x),unit=price(x),total=x.done?num(x.actualTotal||num(x.qty)*unit):num(x.qty)*unit;return `<div class="product-card ${x.done?'is-done':''}"><button class="check ${x.done?'done':''}" data-toggle-shop="${x.id}">${x.done?'✓':''}</button><img class="product-thumb" src="${productImage(x)}" alt="${x.title}"><div class="product-main"><div class="product-title"><h3>${x.title}</h3>${p?`<span>${p.category||''}</span>`:''}</div><p>${x.qty} ${x.unit} · ${x.done?`Comprado ${x.purchaseDate||''}`:`${money(unit)} por ${x.unit}`}</p><div class="product-price"><b>${money(total)}</b>${!x.done&&p?`<button data-compare-shop="${x.id}">Comparar</button>`:''}</div></div><button class="pill-btn" data-edit-shop="${x.id}">•••</button></div>`}
function pantryView(){const q=window.__pantryQ||'',a=state.pantry.filter(x=>(!q||norm(x.name).includes(norm(q)))&&(pantryFilter==='all'||pantryFilter==='low'&&num(x.qty)<=num(x.minQty)||pantryFilter==='stock'&&num(x.qty)>num(x.minQty)));return `<div class="section-head"><div><h2>Despensa</h2><p class="muted">Existencias, consumo y reposición.</p></div><button class="pill-btn" data-new-pantry>＋ Producto</button></div><div class="kpis"><div class="kpi"><small>Productos</small><b>${state.pantry.length}</b></div><div class="kpi"><small>Por reponer</small><b>${state.pantry.filter(x=>num(x.qty)<=num(x.minQty)).length}</b></div><div class="kpi"><small>Vence pronto</small><b>${state.pantry.filter(x=>x.expiry&&((new Date(x.expiry)-new Date())/86400000)<=7).length}</b></div></div><div class="search">⌕<input id="pantrySearch" value="${q}" placeholder="Buscar en la despensa"></div><div class="segments" id="pantryFilters"><button data-filter="all" class="${pantryFilter==='all'?'active':''}">Todos</button><button data-filter="low" class="${pantryFilter==='low'?'active':''}">Por reponer</button><button data-filter="stock" class="${pantryFilter==='stock'?'active':''}">En stock</button></div><div class="list">${a.map(pantryCard).join('')||'<div class="card empty">No hay productos para mostrar.</div>'}</div>`}
function pantryCard(x){const max=Math.max(num(x.minQty)*2,1),pct=Math.min(100,num(x.qty)/max*100),low=num(x.qty)<=num(x.minQty),days=num(x.dailyUse)>0?Math.floor(num(x.qty)/num(x.dailyUse)):null;return `<div class="card pantry-card"><div class="pantry-top"><img class="product-thumb large" src="${productImage(x)}" alt="${x.name}"><div class="main"><h3>${x.name}</h3><p>${x.qty} ${x.pantryUnit||x.unit||'unidad'} · mínimo ${x.minQty||0}</p><span class="stock-chip ${low?'low':'ok'}">${low?'Reponer':'En stock'}</span></div><button class="pill-btn" data-edit-pantry="${x.id}">Editar</button></div><div class="bar ${low?'low':''}"><span style="width:${pct}%"></span></div><div class="pantry-meta"><span>${days!==null?`Dura aprox. ${days} días`:(low?'Requiere reposición':'Stock suficiente')}</span><b>${Math.round(pct)}%</b></div><div class="actions"><button data-consume="${x.id}">Consumir</button><button data-restock="${x.id}">Comprar</button></div></div>`}
function agendaView(){const a=[...state.events].sort((x,y)=>String(x.date||'').localeCompare(String(y.date||''))||String(x.time||'').localeCompare(String(y.time||'')));return `<div class="section-head"><div><h2>Agenda</h2><p class="muted">Citas médicas, salidas, pagos y compromisos con recordatorios.</p></div><button class="pill-btn" data-new-event>＋ Evento</button></div><div class="agenda-summary card"><div><small>PRÓXIMOS 7 DÍAS</small><b>${a.filter(e=>{const d=eventDateTime(e);return d&&d>=new Date()&&d-new Date()<=7*86400000}).length}</b></div><button class="pill-btn" data-open="notifications">Ver avisos</button></div><div class="list">${a.map(x=>`<div class="row-card agenda-card"><div class="icon">${eventIcon(x.type)}</div><div class="main"><div class="event-title-line"><h3>${x.title}</h3><span>${eventTypeLabel(x.type)}</span></div><p>${x.date||'Sin fecha'} ${x.time||''}</p><small class="muted">Recordatorio: ${num(x.reminderMinutes??60)>=1440?'1 día antes':num(x.reminderMinutes??60)>=60?`${Math.round(num(x.reminderMinutes??60)/60)} h antes`:`${num(x.reminderMinutes??60)} min antes`} · ${x.notifyAll===false?'Solo yo':'Compartido'}</small></div><button class="pill-btn" data-edit-event="${x.id}">Editar</button></div>`).join('')||'<div class="card empty">No tienes eventos próximos.</div>'}</div>`}
function moreView(){return `<div class="list"><button class="row-card" data-open="notifications"><div class="icon">🔔</div><div class="main"><h3>Notificaciones</h3><p>${unreadNotifications()} sin leer · agenda y actividad compartida</p></div></button><button class="row-card" data-open="activity"><div class="icon">◷</div><div class="main"><h3>Actividad del hogar</h3><p>Quién agregó, compró o actualizó algo</p></div></button><button class="row-card" data-open="notificationSettings"><div class="icon">⚙</div><div class="main"><h3>Configurar avisos</h3><p>Agenda, mercado, despensa y finanzas</p></div></button><button class="row-card" data-open="tasks"><div class="icon">✓</div><div class="main"><h3>Tareas</h3><p>${state.tasks.length} registradas</p></div></button><button class="row-card" data-open="finance"><div class="icon">S/</div><div class="main"><h3>Centro financiero</h3><p>Proyección, ingresos y gastos</p></div></button><button class="row-card" data-open="salaryPayments"><div class="icon">💵</div><div class="main"><h3>Ingresos programados</h3><p>${state.salaryPayments.filter(x=>x.active!==false).length} pagos activos · ${money(state.salaryPayments.filter(x=>x.active!==false).reduce((s,x)=>s+num(x.amount),0))}</p></div></button><button class="row-card" data-open="extraIncomes"><div class="icon">＋</div><div class="main"><h3>Ingresos extra</h3><p>${money(state.extraIncomes.filter(x=>String(x.date||'').startsWith(today().slice(0,7))).reduce((s,x)=>s+num(x.amount),0))} este mes</p></div></button><button class="row-card" data-open="fixedExpenses"><div class="icon">⌂</div><div class="main"><h3>Gastos fijos</h3><p>${state.fixedExpenses.filter(x=>x.active!==false).length} activos · ${money(fixedTotal())} al mes</p></div></button><button class="row-card" data-open="expenses"><div class="icon">🧾</div><div class="main"><h3>Gastos registrados</h3><p>${money(monthExpenses())} este mes</p></div></button><button class="row-card" data-open="account"><div class="icon">☁</div><div class="main"><h3>Cuenta y sincronización</h3><p>Código ${inviteCode||'—'}</p></div></button><button class="row-card" data-open="backup"><div class="icon">⇩</div><div class="main"><h3>Exportar respaldo</h3><p>Copia JSON de tus datos</p></div></button><div class="card"><small>VERSIÓN ACTUAL</small><h2>v${VERSION}</h2><p class="muted">Versión estable · Firebase · ${catalog().length} productos clasificados</p></div></div>`}

function marketBudgetForm(){openSheet('Presupuesto del mercado',`<form class="form" id="marketBudgetForm"><section class="finance-sheet-hero"><small>PRESUPUESTO MENSUAL ACTUAL</small><b>${money(state.budget)}</b><span>El saldo se calcula restando compras realizadas este mes y productos aún pendientes.</span></section><label>Presupuesto mensual<input name="budget" type="number" min="0" step=".01" value="${num(state.budget)}" required></label><p class="muted">Se reinicia automáticamente el día 1 de cada mes. Las compras anteriores permanecen en el historial.</p><button class="primary">Guardar presupuesto</button></form>`);$('marketBudgetForm').onsubmit=e=>{e.preventDefault();state.budget=num(new FormData(e.currentTarget).get('budget'));addActivity('finance','Actualizó el presupuesto del mercado',money(state.budget),'finance');closeSheet();persist()}}
function marketHistoryCenter(){const done=state.shopping.filter(x=>x.done);const grouped=new Map();for(const x of done){const key=monthKey(purchaseDateOf(x)||today());if(!grouped.has(key))grouped.set(key,[]);grouped.get(key).push(x)}const months=[...grouped.keys()].sort().reverse();openSheet('Historial mensual del mercado',`<section class="finance-sheet-hero"><small>HISTORIAL CONSERVADO</small><b>${done.length} compras</b><span>El presupuesto se reinicia cada mes sin borrar compras, gastos ni movimientos de despensa.</span></section><div class="list market-history-list">${months.map(m=>{const rows=grouped.get(m),total=rows.reduce((s,x)=>s+num(x.actualTotal||num(x.qty)*price(x)),0);const label=new Date(`${m}-01T12:00:00`).toLocaleDateString('es-PE',{month:'long',year:'numeric'});return `<section class="card market-history-month"><div class="section-head compact"><div><small>${label.toUpperCase()}</small><h3>${rows.length} compras</h3></div><b>${money(total)}</b></div>${rows.slice(0,8).map(x=>`<div class="history-purchase-row"><span>${categoryIcon(marketItemCategory(x))} ${x.title}</span><b>${money(x.actualTotal||num(x.qty)*price(x))}</b></div>`).join('')}${rows.length>8?`<p class="muted">y ${rows.length-8} compras más…</p>`:''}</section>`}).join('')||'<div class="card empty">Aún no hay compras realizadas.</div>'}</div>`)}
function pendingShoppingRows(){return state.shopping.filter(x=>!x.done)}
function shoppingListText({includePrices=true,includeSummary=true,groupCategories=true}={}){
  const rows=pendingShoppingRows();
  const t=marketTotals();
  const store=state.preferredStore;
  const lines=[`🛒 LISTA DE COMPRAS · NUESTRO ESPACIO`,`📅 ${new Date().toLocaleDateString('es-PE',{dateStyle:'long'})}`,`🏪 Referencia: ${STORE_LABELS[store]}`,''];
  if(!rows.length){lines.push('No hay productos pendientes.');return lines.join('\n')}
  if(groupCategories){
    for(const group of groupedMarketRows(rows)){
      lines.push(`${categoryIcon(group.category)} ${group.category.toUpperCase()}:`);
      group.items.forEach(x=>{const subtotal=num(x.qty)*price(x);lines.push(`☐ ${x.title} — ${x.qty} ${x.unit}${includePrices?` · ${money(subtotal)}`:''}`)});
      lines.push('');
    }
  }else rows.forEach((x,i)=>{const subtotal=num(x.qty)*price(x);lines.push(`${i+1}. ☐ ${x.title} — ${x.qty} ${x.unit}${includePrices?` · ${money(subtotal)}`:''}`)});
  if(includeSummary){lines.push(`Productos pendientes: ${rows.length}`);if(includePrices){const b=marketBudgetStatus();lines.push(`Gastado este mes: ${money(b.spent)}`,`Pendiente ${STORE_LABELS[store]}: ${money(t[store])}`,`Rango pendiente: ${money(t.min)} – ${money(t.max)}`,`Presupuesto mensual: ${money(state.budget)}`,`${b.remaining>=0?'Saldo mensual disponible':'Exceso mensual'}: ${money(Math.abs(b.remaining))}`)}}
  lines.push('','Compartido desde Nuestro Espacio');return lines.join('\n')
}
async function copyTextReliable(text){
  try{await navigator.clipboard.writeText(text);return true}catch{}
  try{const ta=document.createElement('textarea');ta.value=text;ta.style.position='fixed';ta.style.opacity='0';document.body.appendChild(ta);ta.select();const ok=document.execCommand('copy');ta.remove();return ok}catch{return false}
}
async function nativeShareShopping(options={}){
  const text=shoppingListText(options);
  if(navigator.share){try{await navigator.share({title:'Lista de compras · Nuestro Espacio',text});return}catch(e){if(e?.name==='AbortError')return}}
  const ok=await copyTextReliable(text);toast(ok?'Lista copiada para compartir':'No se pudo compartir')
}
function whatsappShopping(options={}){const text=shoppingListText(options);window.open(`https://wa.me/?text=${encodeURIComponent(text)}`,'_blank','noopener')}
function downloadShoppingTxt(options={}){const text=shoppingListText(options),blob=new Blob([text],{type:'text/plain;charset=utf-8'}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=`lista-compras-${today()}.txt`;a.click();setTimeout(()=>URL.revokeObjectURL(url),1000);toast('Reporte descargado')}
function printShoppingReport(options={}){
  const rows=pendingShoppingRows(),t=marketTotals(),store=state.preferredStore,w=window.open('','_blank');if(!w)return toast('Safari bloqueó la ventana del reporte');
  let index=0;const items=groupedMarketRows(rows).map(group=>`<tr class="category-row"><td colspan="5">${categoryIcon(group.category)} ${group.category}</td></tr>${group.items.map(x=>`<tr><td>${++index}</td><td>☐</td><td><strong>${x.title}</strong></td><td>${x.qty} ${x.unit}</td><td>${options.includePrices!==false?money(num(x.qty)*price(x)):'—'}</td></tr>`).join('')}`).join('');
  w.document.write(`<!doctype html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width"><title>Lista de compras</title><style>body{font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;margin:36px;color:#171717}header{border-bottom:2px solid #111;padding-bottom:18px;margin-bottom:24px}h1{margin:0 0 8px}.meta{color:#666}.summary{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0}.box{border:1px solid #ddd;border-radius:14px;padding:14px}.box b{display:block;font-size:20px;margin-top:5px}table{width:100%;border-collapse:collapse}th,td{text-align:left;border-bottom:1px solid #ddd;padding:12px 6px}th{font-size:12px;text-transform:uppercase;color:#666}.category-row td{background:#f1f3f5;font-weight:800;font-size:14px;padding:12px;border-top:12px solid #fff}footer{margin-top:28px;color:#777;font-size:12px}@media print{button{display:none}body{margin:18px}}@media(max-width:600px){.summary{grid-template-columns:1fr}}</style></head><body><header><h1>Lista de compras</h1><div class="meta">Nuestro Espacio · ${new Date().toLocaleDateString('es-PE',{dateStyle:'long'})} · ${STORE_LABELS[store]}</div></header><div class="summary"><div class="box">Productos pendientes<b>${rows.length}</b></div><div class="box">Gastado este mes<b>${money(marketBudgetStatus().spent)}</b></div><div class="box">Saldo mensual<b>${money(marketBudgetStatus().remaining)}</b></div></div><table><thead><tr><th>#</th><th></th><th>Producto</th><th>Cantidad</th><th>Estimado</th></tr></thead><tbody>${items||'<tr><td colspan="5">No hay productos pendientes.</td></tr>'}</tbody></table><footer>Lista agrupada por categorías. Estimación referencial; los precios pueden variar según tienda, distrito, presentación y promociones.</footer><script>setTimeout(()=>window.print(),350)<\/script></body></html>`);w.document.close()
}
function shareShoppingCenter(){
  const count=pendingShoppingRows().length,t=marketTotals();
  const mb=marketBudgetStatus();openSheet('Compartir lista de compras',`<section class="share-summary card"><small>LISTA PENDIENTE</small><h2>${count} productos</h2><p>${money(t[state.preferredStore])} pendientes · ${money(mb.spent)} gastados este mes · saldo ${money(mb.remaining)}</p></section><form class="form" id="shareOptions"><label class="switch-row"><span>Agrupar por categorías</span><input type="checkbox" name="groupCategories" checked></label><label class="switch-row"><span>Incluir precios estimados</span><input type="checkbox" name="includePrices" checked></label><label class="switch-row"><span>Incluir presupuesto y resumen</span><input type="checkbox" name="includeSummary" checked></label></form><div class="share-actions"><button class="primary" id="nativeShareList">↗ Compartir por Mensajes, WhatsApp y más</button><button class="share-action" id="whatsappList"><span>💬</span><div><b>Abrir WhatsApp</b><small>Enviar la lista ordenada por categorías</small></div></button><button class="share-action" id="copyShoppingList"><span>⧉</span><div><b>Copiar lista</b><small>Pegarla en cualquier aplicación</small></div></button><button class="share-action" id="printShoppingList"><span>▤</span><div><b>Reporte por categorías</b><small>Imprimir o guardar como PDF desde iPhone</small></div></button><button class="share-action" id="downloadShoppingList"><span>⇩</span><div><b>Descargar TXT</b><small>Archivo ligero y compatible</small></div></button></div><div class="card share-preview"><small>VISTA PREVIA</small><pre id="shoppingSharePreview"></pre></div>`);
  const options=()=>{const f=new FormData($('shareOptions'));return{groupCategories:f.has('groupCategories'),includePrices:f.has('includePrices'),includeSummary:f.has('includeSummary')}};
  const update=()=>{$('shoppingSharePreview').textContent=shoppingListText(options())};update();$('shareOptions').onchange=update;
  $('nativeShareList').onclick=()=>nativeShareShopping(options());$('whatsappList').onclick=()=>whatsappShopping(options());$('copyShoppingList').onclick=async()=>toast(await copyTextReliable(shoppingListText(options()))?'Lista copiada':'No se pudo copiar');$('printShoppingList').onclick=()=>printShoppingReport(options());$('downloadShoppingList').onclick=()=>downloadShoppingTxt(options())
}
function bindView(){$('shareMarketList')?.addEventListener('click',shareShoppingCenter);$('copyMarketQuick')?.addEventListener('click',async()=>toast(await copyTextReliable(shoppingListText())?'Lista copiada':'No se pudo copiar'));$('marketHistoryBtn')?.addEventListener('click',marketHistoryCenter);$('editMarketBudget')?.addEventListener('click',marketBudgetForm);document.querySelectorAll('[data-go]').forEach(b=>b.onclick=()=>go(b.dataset.go));$('marketSearch')?.addEventListener('input',e=>{marketSearch=e.target.value;render()});$('marketFilters')?.addEventListener('click',e=>{const b=e.target.closest('button');if(b){marketFilter=b.dataset.filter;render()}});$('marketCategoryFilters')?.addEventListener('click',e=>{const b=e.target.closest('button[data-category]');if(b){marketCategory=b.dataset.category;render()}});$('storeSeg')?.addEventListener('click',e=>{const b=e.target.closest('button');if(b){state.preferredStore=b.dataset.store;persist()}});$('pantrySearch')?.addEventListener('input',e=>{window.__pantryQ=e.target.value;render()});$('pantryFilters')?.addEventListener('click',e=>{const b=e.target.closest('button');if(b){pantryFilter=b.dataset.filter;render()}});document.querySelectorAll('[data-toggle-shop]').forEach(b=>b.onclick=()=>toggleShop(b.dataset.toggleShop));document.querySelectorAll('[data-edit-shop]').forEach(b=>b.onclick=()=>shopForm(b.dataset.editShop));document.querySelectorAll('[data-compare-shop]').forEach(b=>b.onclick=()=>compareSheet(b.dataset.compareShop));document.querySelectorAll('[data-new-pantry]').forEach(b=>b.onclick=()=>pantryForm());document.querySelectorAll('[data-edit-pantry]').forEach(b=>b.onclick=()=>pantryForm(b.dataset.editPantry));document.querySelectorAll('[data-consume]').forEach(b=>b.onclick=()=>consumeForm(b.dataset.consume));document.querySelectorAll('[data-restock]').forEach(b=>b.onclick=()=>restock(b.dataset.restock));document.querySelectorAll('[data-new-event]').forEach(b=>b.onclick=()=>eventForm());document.querySelectorAll('[data-edit-event]').forEach(b=>b.onclick=()=>eventForm(b.dataset.editEvent));document.querySelectorAll('[data-open]').forEach(b=>b.onclick=()=>moreAction(b.dataset.open))}
function openSheet(title,html){$('sheetTitle').textContent=title;$('sheetBody').innerHTML=html;show($('sheet'),true);document.body.style.overflow='hidden'}function closeSheet(){show($('sheet'),false);document.body.style.overflow=''}$('sheetClose').onclick=closeSheet;$('sheet').onclick=e=>{if(e.target===$('sheet'))closeSheet()};
const units=['kg','g','litro','ml','unidad','unidades','docena','bolsa','paquete','botella','lata','frasco','caja','porciones'];function opts(sel){return units.map(u=>`<option ${u===sel?'selected':''}>${u}</option>`).join('')}
function shopForm(id=''){
  const x=state.shopping.find(x=>x.id===id)||{id:'',title:'',qty:1,unit:'unidad',unitPrice:0,category:'Otros',productId:''};
  const initial=catalog().find(p=>p.id===x.productId)||catalog().find(p=>norm(p.name)===norm(x.title));
  const initialCategory=inferMarketCategory(x.title||initial?.name||'',initial?.category||x.category||'Otros');
  const suggested=initial?num(initial[state.preferredStore]):num(x.unitPrice);
  openSheet(id?'Editar compra':'Nueva compra',`<form class="form" id="sf">
    <input type="hidden" name="id" value="${x.id}">
    <input type="hidden" name="productId" id="sfProductId" value="${x.productId||initial?.id||''}">
    <label>Producto
      <input name="title" id="sfTitle" value="${x.title}" required autocomplete="off" placeholder="Ej. tomate, arroz, leche">
    </label>
    <div id="catalogSuggest" class="catalog-suggest" hidden></div>
    <div id="pricePreview" class="price-preview"></div>
    <div class="two">
      <label>Cantidad<input name="qty" id="sfQty" type="number" step=".01" min="0.01" value="${x.qty}" required></label>
      <label>Unidad<select name="unit" id="sfUnit">${opts(x.unit||initial?.unit||'unidad')}</select></label>
    </div>
    <label>Categoría<select name="category" id="sfCategory">${sortCategories(new Set([...MARKET_CATEGORY_ORDER,...catalog().map(p=>p.category||'Otros'),initialCategory])).map(c=>`<option value="${c}" ${initialCategory===c?'selected':''}>${categoryIcon(c)} ${c}</option>`).join('')}</select></label>
    <label>Precio por unidad
      <div class="money-input"><span>S/</span><input name="unitPrice" id="sfUnitPrice" type="number" min="0" step=".01" value="${(num(x.unitPrice)||suggested||0).toFixed(2)}"></div>
      <small class="muted">Puedes editarlo si el precio real es distinto.</small>
    </label>
    <div class="form-total" id="sfTotal"></div>
    <button class="primary">Guardar</button>
    ${id?'<button type="button" class="primary danger" id="delShop">Eliminar</button>':''}
  </form>`);

  const title=$('sfTitle'), unit=$('sfUnit'), category=$('sfCategory'), unitPrice=$('sfUnitPrice'), productId=$('sfProductId'), suggest=$('catalogSuggest'), preview=$('pricePreview'), qty=$('sfQty'), total=$('sfTotal');
  let selected=initial||null;

  function storeLabel(k){return k==='market'?'Mercado':k==='supermarket'?'Supermercado':'Mayorista'}
  function renderPreview(p){
    if(!p){preview.innerHTML='<div class="catalog-empty">Producto sin precio del catálogo. Ingresa el precio manualmente.</div>';return}
    preview.innerHTML=`<div class="price-preview-head"><div><b>${p.name}</b><small>${p.category||'Producto'} · por ${p.unit||'unidad'}</small></div><span class="price-badge">${storeLabel(state.preferredStore)}</span></div><div class="price-grid"><button type="button" data-pick-price="market"><small>Mercado</small><b>${money(p.market)}</b></button><button type="button" data-pick-price="supermarket"><small>Supermercado</small><b>${money(p.supermarket)}</b></button><button type="button" data-pick-price="wholesale"><small>Mayorista</small><b>${money(p.wholesale)}</b></button></div>`;
    preview.querySelectorAll('[data-pick-price]').forEach(b=>b.onclick=()=>{const k=b.dataset.pickPrice;unitPrice.value=num(p[k]).toFixed(2);updateTotal();preview.querySelectorAll('button').forEach(x=>x.classList.toggle('active',x===b))});
    const active=preview.querySelector(`[data-pick-price="${state.preferredStore}"]`);if(active)active.classList.add('active');
  }
  function choose(p){selected=p;title.value=p.name;productId.value=p.id;unit.value=p.unit||'unidad';category.value=p.category||'Otros';unitPrice.value=num(p[state.preferredStore]).toFixed(2);suggest.hidden=true;renderPreview(p);updateTotal()}
  function showSuggestions(){
    const q=norm(title.value);if(!q){suggest.hidden=true;return}
    const matches=catalog().filter(p=>norm(p.name).includes(q)).slice(0,8);
    if(!matches.length){suggest.hidden=true;return}
    suggest.innerHTML=matches.map(p=>`<button type="button" data-catalog-id="${p.id}"><span><b>${p.name}</b><small>${p.category||''} · ${p.unit||'unidad'}</small></span><strong>${money(p[state.preferredStore])}</strong></button>`).join('');
    suggest.hidden=false;suggest.querySelectorAll('[data-catalog-id]').forEach(b=>b.onclick=()=>choose(catalog().find(p=>p.id===b.dataset.catalogId)));
  }
  function detectExact(){const p=catalog().find(p=>norm(p.name)===norm(title.value));if(p){choose(p)}else{selected=null;productId.value='';renderPreview(null);updateTotal()}}
  function updateTotal(){total.innerHTML=`<span>Subtotal estimado</span><strong>${money(num(qty.value)*num(unitPrice.value))}</strong>`}

  title.addEventListener('input',()=>{selected=null;productId.value='';showSuggestions()});
  title.addEventListener('change',detectExact);
  title.addEventListener('blur',()=>setTimeout(()=>{suggest.hidden=true;detectExact()},180));
  qty.addEventListener('input',updateTotal);unitPrice.addEventListener('input',updateTotal);
  renderPreview(initial||null);updateTotal();

  $('sf').onsubmit=e=>{
    e.preventDefault();const o=Object.fromEntries(new FormData(e.currentTarget));o.qty=num(o.qty);o.unitPrice=num(o.unitPrice);
    const p=catalog().find(p=>p.id===o.productId)||catalog().find(p=>norm(p.name)===norm(o.title));
    if(p){o.productId=p.id;o.title=p.name;o.unit=o.unit||p.unit;o.category=p.category||x.category||'Otros';if(!o.unitPrice)o.unitPrice=num(p[state.preferredStore])}
    else{o.productId=x.productId||'';o.category=o.category||x.category||'Otros'}
    o.done=x.done||false;if(id){Object.assign(x,o);addActivity('market',`Actualizó ${o.title}`,`${o.qty} ${o.unit}`,'shared',x.id)}else{o.id=uid();state.shopping.unshift(o);addActivity('market',`Agregó ${o.title} al mercado`,`${o.qty} ${o.unit}`,'shared',o.id)}closeSheet();persist()
  };
  $('delShop')?.addEventListener('click',()=>{const item=state.shopping.find(v=>v.id===id);if(item?.done)rollbackPurchase(item);state.shopping=state.shopping.filter(v=>v.id!==id);if(item)addActivity('market',`Eliminó ${item.title} del mercado`,'','shared',id);closeSheet();persist()})
}
function toggleShop(id){const x=state.shopping.find(x=>x.id===id);if(!x)return;if(!x.done)return completePurchase(x);rollbackPurchase(x);persist()}
function completePurchase(x){openSheet('Confirmar compra',`<form class="form" id="complete"><p>${x.title} · ${x.qty} ${x.unit}</p><label>Total pagado<input name="amount" type="number" step=".01" value="${(x.qty*price(x)).toFixed(2)}"></label><label>Cantidad a despensa<input name="pantryQty" type="number" step=".01" value="${x.qty}"></label><label>Unidad de despensa<select name="pantryUnit">${opts(x.pantryUnit||x.unit)}</select></label><button class="primary">Guardar compra</button></form>`);$('complete').onsubmit=e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.currentTarget)),eid=uid();x.done=true;x.actualTotal=num(o.amount);x.purchaseDate=today();x.purchaseMonth=monthKey();x.linkedExpenseId=eid;x.pantryAddQty=num(o.pantryQty);x.pantryUnit=o.pantryUnit;state.expenses.unshift({id:eid,sourcePurchaseId:x.id,title:'Mercado: '+x.title,amount:x.actualTotal,date:today(),category:'Mercado'});let p=state.pantry.find(p=>norm(p.name)===norm(x.title));if(!p){p={id:uid(),name:x.title,qty:0,minQty:0,unit:x.pantryUnit,pantryUnit:x.pantryUnit,purchaseUnit:x.unit,conversionRate:x.qty?x.pantryAddQty/x.qty:1};state.pantry.unshift(p)}p.qty=num(p.qty)+x.pantryAddQty;x.pantryMovement={itemId:p.id,qty:x.pantryAddQty};addActivity('purchase',`Compró ${x.title}`,`${x.pantryAddQty} ${x.pantryUnit} añadidos a despensa · ${money(x.actualTotal)}`,'shared',x.id);closeSheet();persist()}}
function rollbackPurchase(x){x.done=false;if(x.linkedExpenseId)state.expenses=state.expenses.filter(e=>e.id!==x.linkedExpenseId);if(x.pantryMovement){const p=state.pantry.find(p=>p.id===x.pantryMovement.itemId);if(p)p.qty=Math.max(0,num(p.qty)-num(x.pantryMovement.qty))}delete x.linkedExpenseId;delete x.pantryMovement;delete x.purchaseMonth;delete x.purchaseDate;delete x.actualTotal;delete x.pantryAddQty;addActivity('purchase',`Revirtió la compra de ${x.title}`,'Se retiró el gasto y el movimiento de despensa','shared',x.id)}
function pantryForm(id=''){const x=state.pantry.find(x=>x.id===id)||{name:'',qty:0,minQty:0,unit:'unidad',pantryUnit:'unidad',purchaseUnit:'unidad',conversionRate:1,dailyUse:0,expiry:''};openSheet(id?'Editar producto':'Nuevo producto',`<form class="form" id="pf"><label>Producto<input name="name" value="${x.name}" required></label><div class="two"><label>Cantidad<input name="qty" type="number" step=".01" value="${x.qty}"></label><label>Mínimo<input name="minQty" type="number" step=".01" value="${x.minQty}"></label></div><div class="two"><label>Unidad de despensa<select name="pantryUnit">${opts(x.pantryUnit||x.unit)}</select></label><label>Unidad de compra<select name="purchaseUnit">${opts(x.purchaseUnit||x.unit)}</select></label></div><div class="two"><label>Unidades por compra<input name="conversionRate" type="number" step=".01" value="${x.conversionRate||1}"></label><label>Consumo diario<input name="dailyUse" type="number" step=".01" value="${x.dailyUse||0}"></label></div><label>Vencimiento<input name="expiry" type="date" value="${x.expiry||''}"></label><button class="primary">Guardar</button>${id?'<button type="button" class="primary danger" id="delPantry">Eliminar</button>':''}</form>`);$('pf').onsubmit=e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.currentTarget));['qty','minQty','conversionRate','dailyUse'].forEach(k=>o[k]=num(o[k]));o.unit=o.pantryUnit;if(id){Object.assign(x,o);addActivity('pantry',`Actualizó ${o.name} en despensa`,`${o.qty} ${o.pantryUnit}`,'shared',id)}else{o.id=uid();state.pantry.unshift(o);addActivity('pantry',`Añadió ${o.name} a despensa`,`${o.qty} ${o.pantryUnit}`,'shared',o.id)}closeSheet();persist()};$('delPantry')?.addEventListener('click',()=>{state.pantry=state.pantry.filter(v=>v.id!==id);closeSheet();persist()})}
function consumeForm(id){const x=state.pantry.find(x=>x.id===id);openSheet('Consumir '+x.name,`<form class="form" id="cf"><p>Disponible: <b>${x.qty} ${x.pantryUnit||x.unit}</b></p><label>Cantidad<input name="qty" type="number" step=".01" required></label><label>Unidad<select name="unit">${opts(x.pantryUnit||x.unit)}</select></label><button class="primary">Confirmar consumo</button></form>`);$('cf').onsubmit=e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.currentTarget));let q=num(o.qty),base=x.pantryUnit||x.unit;if(base==='kg'&&o.unit==='g')q/=1000;if(base==='litro'&&o.unit==='ml')q/=1000;if(q>x.qty)return toast('No hay suficiente stock');x.qty=Math.max(0,x.qty-q);addActivity('pantry',`Consumió ${x.name}`,`${q} ${base} · quedan ${x.qty} ${base}`,'shared',x.id);if(x.qty<=num(x.minQty)&&prefs().pantry!==false){state.notifications.unshift({id:uid(),type:'pantry-low',title:`${x.name} necesita reposición`,body:`Quedan ${x.qty} ${base}; mínimo ${x.minQty} ${base}`,category:'pantry',entityId:x.id,actorId:'system',actorName:'Despensa',createdAt:new Date().toISOString(),readBy:[]})}closeSheet();persist()}}
function restock(id){const x=state.pantry.find(x=>x.id===id),need=Math.max(0,num(x.minQty)-num(x.qty));if(!need)return toast('Stock suficiente');const qty=need/(num(x.conversionRate)||1),e=state.shopping.find(s=>!s.done&&norm(s.title)===norm(x.name));if(e)e.qty+=qty;else state.shopping.unshift({id:uid(),title:x.name,qty,unit:x.purchaseUnit||x.unit,productId:'',unitPrice:0,done:false});addActivity('market',`Añadió ${x.name} al mercado desde despensa`,`${qty.toFixed(2)} ${x.purchaseUnit||x.unit}`,'shared',x.id);persist();toast('Añadido al mercado')}
function eventForm(id=''){const x=state.events.find(e=>e.id===id)||{title:'',date:today(),time:'09:00',type:'medical',reminderMinutes:60,notifyAll:true,notes:''};openSheet(id?'Editar evento':'Nuevo evento',`<form class="form" id="ef"><label>Título<input name="title" value="${x.title||''}" required placeholder="Ej. Control médico"></label><div class="two"><label>Fecha<input name="date" type="date" value="${x.date||today()}" required></label><label>Hora<input name="time" type="time" value="${x.time||'09:00'}"></label></div><label>Tipo<select name="type">${[['medical','Cita médica'],['outing','Salida'],['payment','Pago'],['family','Familia'],['work','Trabajo'],['other','Otro']].map(([v,l])=>`<option value="${v}" ${x.type===v?'selected':''}>${l}</option>`).join('')}</select></label><label>Recordarme<select name="reminderMinutes">${[[0,'A la hora'],[15,'15 minutos antes'],[30,'30 minutos antes'],[60,'1 hora antes'],[120,'2 horas antes'],[1440,'1 día antes'],[2880,'2 días antes']].map(([v,l])=>`<option value="${v}" ${num(x.reminderMinutes??60)===v?'selected':''}>${l}</option>`).join('')}</select></label><label class="switch-row"><span>Notificar a ambos</span><input type="checkbox" name="notifyAll" ${x.notifyAll!==false?'checked':''}></label><label>Notas<textarea name="notes" rows="3" placeholder="Dirección, indicaciones o detalles">${x.notes||''}</textarea></label><button class="primary">Guardar evento</button>${id?'<button type="button" class="primary danger" id="deleteEvent">Eliminar evento</button>':''}</form>`);$('ef').onsubmit=e=>{e.preventDefault();const f=new FormData(e.currentTarget),o=Object.fromEntries(f);o.reminderMinutes=num(o.reminderMinutes);o.notifyAll=f.has('notifyAll');delete o.lastReminderKey;if(id){Object.assign(x,o);addActivity('agenda',`Actualizó: ${o.title}`,`${o.date} ${o.time||''}`,'agenda',id)}else{o.id=uid();state.events.unshift(o);addActivity('agenda',`Agendó: ${o.title}`,`${eventTypeLabel(o.type)} · ${o.date} ${o.time||''}`,'agenda',o.id)}closeSheet();persist();checkAgendaReminders()};$('deleteEvent')?.addEventListener('click',()=>{state.events=state.events.filter(e=>e.id!==id);addActivity('agenda',`Eliminó: ${x.title}`,'','agenda',id);closeSheet();persist()})}

